arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(1)
  if bActive=true
  {
    if bTargetFound=false
    {
      bTargetFound=true
      seekTime=seekMax
    }
    seekTime-=1
    if seekTime>0 //Extend spike
    {
      extendDist-=seekSpeed
      yCheck-=seekSpeed
    }
    else if seekTime<-waitTime
    {
      if yCheck=ySPlace
      {
        if seekTime<(round(-waitTime*2))
        {
          bTargetFound=false
          bActive=false
        }
      }
      else //Retract spike
      {
        extendDist+=seekSpeed
        yCheck+=seekSpeed
      }
    }
    image_yscale=-1-extendDist
  }
}
